      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      expect(result.explainabilityTrace.configurationRefs.attributeInfluence).toBe(
        'processingConfig.attributeRelevance'
      );
    });

    test('should preserve existing context data', () => {
      const originalContext = { ...mockContext };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      // Original context should be preserved
      expect(mockContext.emailId).toBe(originalContext.emailId);
      expect(mockContext.detectionMetadata).toEqual(originalContext.detectionMetadata);
      expect(result).toBeDefined();
    });
  });

  describe('Error Handling and Edge Cases', () => {
    test('should handle missing attribute relevance configuration', () => {
      // Create config without attribute relevance configuration
      const configWithoutAttributeRelevance = {
        ...mockConfig,
        processingConfig: {
          ...mockConfig.processingConfig,
        },
      };
      // Remove the property to simulate missing configuration
      delete (
        configWithoutAttributeRelevance.processingConfig as Partial<
          typeof configWithoutAttributeRelevance.processingConfig
        >
      ).attributeRelevance;

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;

      expect(() => executeAttributeInfluence(mockEmail, session, result, configWithoutAttributeRelevance)).toThrow(
        'Attribute relevance configuration not found'
      );
    });

    test('should handle unknown attributes gracefully', () => {
      // Add unknown attribute to context
      mockContext.detectionMetadata.unknownAttribute = {
        detectedAt: new Date(),
        detectionMethod: 'derived',
        confidence: 0.5,
        parallelProcessed: false,
        dependencies: [],
        sourceField: 'body',
        matchedValue: 'unknown',
        detectorConfig: {
          field: 'body',
          operation: 'unknown',
          values: ['unknown'],
          weight: 1.0,
          cacheEnabled: true,
          parallelSafe: true,
        },
        detectionTimeMs: 1,
        cacheUsed: false,
        retryCount: 0,
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      // Should not crash, unknown attributes ignored
      expect(result.attributeContext.influenceApplications).not.toContainEqual(
        expect.objectContaining({
          attributeUsed: 'unknownAttribute',
        })
      );
    });

    test('should handle empty detection metadata', () => {
      mockContext.detectionMetadata = {};

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      expect(result.attributeContext.influenceApplications).toHaveLength(0);
      expect(result.explainabilityTrace.stageTimings.attributeInfluence).toBeGreaterThanOrEqual(0);
    });

    test('should validate role configurations', () => {
      // Invalid role in configuration
      if ('categoryRoles' in mockConfig.processingConfig.attributeRelevance.FINANCIAL) {
        mockConfig.processingConfig.attributeRelevance.FINANCIAL.categoryRoles.financialDomain =
          'INVALID_ROLE' as AttributeRole;
      }

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;

      expect(() => executeAttributeInfluence(mockEmail, session, result, mockConfig)).toThrow(
        'Invalid attribute role: INVALID_ROLE'
      );
    });
  });

  describe('Integration with Previous Stages', () => {
    test('should work with attribute detection results', () => {
      // Simulate typical attribute detection output
      mockContext.detectionMetadata = {
        financialDomain: {
          detectedAt: new Date(),
          detectionMethod: 'domainLookup',
          confidence: 0.95,
          parallelProcessed: false,
          dependencies: [],
          sourceField: 'from.address',
          matchedValue: 'financial.com',
          detectorConfig: {
            field: 'from.address',
            operation: 'domainExtract',
            values: ['financial.com'],
            weight: 1.0,
            cacheEnabled: true,
            parallelSafe: true,
          },
          detectionTimeMs: 5,
          cacheUsed: false,
          retryCount: 0,
        },
        invoicePattern: {
          detectedAt: new Date(),
          detectionMethod: 'pattern',
          confidence: 0.88,
          parallelProcessed: false,
          dependencies: [],
          sourceField: 'body',
          matchedValue: 'invoice',
          detectorConfig: {
            field: 'body',
            operation: 'regexPattern',
            values: ['invoice'],
            weight: 1.0,
            cacheEnabled: true,
            parallelSafe: true,
          },
          detectionTimeMs: 3,
          cacheUsed: false,
          retryCount: 0,
        },
        endOfMonth: {
          detectedAt: new Date(),
          detectionMethod: 'derived',
          confidence: 0.72,
          parallelProcessed: false,
          dependencies: [],
          sourceField: 'date',
          matchedValue: 'endOfMonth',
          detectorConfig: {
            field: 'date',
            operation: 'temporalAnalysis',
            values: ['endOfMonth'],
            weight: 1.0,
            cacheEnabled: true,
            parallelSafe: true,
          },
          detectionTimeMs: 1,
          cacheUsed: false,
          retryCount: 0,
        },
      };

      const { session, result } = setupTest();
      result.emailId = mockEmail.id;
      executeAttributeInfluence(mockEmail, session, result, mockConfig);

      // Should process all detected attributes with appropriate roles
      // 3 attributes but some attributes apply to both category and subtype levels
      expect(result.attributeContext.influenceApplications.length).toBeGreaterThan(0);

      const financialInfluences = result.attributeContext.influenceApplications.filter(
        (app) => app.targetCategory === 'FINANCIAL'
      );
      expect(financialInfluences.length).toBeGreaterThan(0); // Should have financial influences
    });

    test('should preserve stage chain data', () => {
      // Simulate data from previous stages
      const emailWithStageData = {
        ...mockEmail,
        stageResults: {
          hardAssertions: { completed: true },
          strongIndicators: { completed: true },
          ruleScoring: { completed: true },
          attributeDetection: { completed: true },
        },
      } as TestEmailMessage;

      const { session, result } = setupTest();
      result.emailId = emailWithStageData.id;
      executeAttributeInfluence(emailWithStageData, session, result, mockConfig);

      // Should have attribute influence execution tracked
      expect(result.explainabilityTrace.configurationRefs.attributeInfluence).toBeDefined();
      expect(result.explainabilityTrace.stageTimings.attributeInfluence).toBeGreaterThanOrEqual(0);
      expect(result).toBeDefined();
    });
  });
});

