 *
 * Focused tests that verify the core StageTask functionality
 * without requiring complete pipeline execution.
 */

import { ClassificationPipeline } from '../../src/pipeline/classification-pipeline';
import { EmailMessage } from '../../src/types/email-message';
import { CategoryConfiguration } from '../../src/types/category-configuration';

describe('StageTask Basic Architecture', () => {
  // Minimal mock configuration with correct TypeScript types
  const mockConfig: CategoryConfiguration = {
    version: '1.0',
    processingConfig: {
      version: 1,
      taxonomyNotes: 'Basic test config',
