          STRUCTURAL: 'Structural',
          DERIVED_LINK: 'Derived link',
          NEUTRAL: 'Neutral',
        },
      },
      attributes: {
        schema: {},
        detectors: [],
        derived: {},
        attributeBonusMap: {},
      },
      aiPrompts: {
        featureExtraction: { systemPrompt: [''], userPrompt: [''] },
        finalClassification: { systemPrompt: [''], userPrompt: [''] },
      },
      featureExtractionSchema: {
        type: 'object',
        properties: {},
        required: [],
      },
    },
    lastModified: new Date(),
    hash: 'test-config-hash',
    schemaVersion: '1.0',
    validationPassed: true,
    validationErrors: [],
    compiledRules: [],
    attributeMatrix: {},
  };

  const mockEmail: EmailMessage = {
    id: 'basic-test-001',
    threadId: 'thread-001',
    gmailLabels: [],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: 'Test Email' },
        { name: 'From', value: 'test@example.com' },
      ],
      body: { data: 'VGVzdA==', size: 4 },
    },
    subject: 'Test Email',
    from: { email: 'test@example.com', name: 'Test', raw: 'test@example.com' },
    to: [],
    date: new Date(),
    bodyPlain: 'Test',
    isProcessed: false,
    processingPriority: 1,
  };

  let pipeline: ClassificationPipeline;

  beforeEach(() => {
    pipeline = new ClassificationPipeline(mockConfig, true);
  });

  describe('Interface Verification', () => {
    it('should have classifyWithStageTask method', () => {
      expect(typeof pipeline.classifyWithStageTask).toBe('function');
    });

    it('should have existing classify method', () => {
      expect(typeof pipeline.classify).toBe('function');
    });

    it('should have existing classifyBatch method', () => {
      expect(typeof pipeline.classifyBatch).toBe('function');
    });
  });

  describe('Stage Logging Verification', () => {
    it('should log stage execution in test mode', async () => {
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation();

      try {
        // We expect this to fail at some stage, but we can verify initial logging
        await pipeline.classifyWithStageTask(mockEmail, 'strong-indicators');
      } catch {
        // Expected to fail at some point
      }

      try {
        const allLogs = consoleSpy.mock.calls.map((call) => call[0]);

        // Should have skipped hard-assertions
        expect(allLogs.some((log) => log.includes('Skipping stage: hard-assertions'))).toBe(true);

        // Should execute strong-indicators
        expect(allLogs.some((log) => log.includes('Executing stage: strong-indicators'))).toBe(true);
      } finally {
        consoleSpy.mockRestore();
      }
    });

    it('should not skip stages when no replay specified', async () => {
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation();

      try {
        await pipeline.classifyWithStageTask(mockEmail);
      } catch {
        // Expected to fail
      }

      try {
        const allLogs = consoleSpy.mock.calls.map((call) => call[0]);

        // Should start with hard-assertions (no skipping)
        expect(allLogs.some((log) => log.includes('Executing stage: hard-assertions'))).toBe(true);

        // Should not have any skip messages
        const skipLogs = allLogs.filter((log) => log.includes('Skipping stage:'));
        expect(skipLogs.length).toBe(0);
      } finally {
        consoleSpy.mockRestore();
      }
    });
  });

  describe('Error Handling', () => {
    it('should provide descriptive error messages', async () => {
      await expect(pipeline.classifyWithStageTask(mockEmail)).rejects.toThrow(/Classification pipeline failed/);
    });

    it('should handle invalid email gracefully', async () => {
      const invalidEmail = { ...mockEmail, id: '' };

      await expect(pipeline.classifyWithStageTask(invalidEmail)).rejects.toThrow();
    });
  });

  describe('Method Integration', () => {
    it('should maintain API compatibility', () => {
      // Both old and new methods should exist and be callable
      expect(pipeline.classify).toBeDefined();
      expect(pipeline.classifyBatch).toBeDefined();
      expect(pipeline.classifyWithStageTask).toBeDefined();
    });

    it('should return promises from all methods', () => {
      const classifyPromise = pipeline.classify(mockEmail);
      const batchPromise = pipeline.classifyBatch([mockEmail]);
      const stageTaskPromise = pipeline.classifyWithStageTask(mockEmail);

      expect(classifyPromise).toBeInstanceOf(Promise);
      expect(batchPromise).toBeInstanceOf(Promise);
      expect(stageTaskPromise).toBeInstanceOf(Promise);

      // Clean up promises to avoid unhandled rejections
      classifyPromise.catch(() => {});
      batchPromise.catch(() => {});
      stageTaskPromise.catch(() => {});
    });
  });

  describe('Architecture Verification', () => {
    it('should successfully instantiate with valid config', () => {
      expect(pipeline).toBeInstanceOf(ClassificationPipeline);
    });

    it('should respect test mode flag', () => {
      const testPipeline = new ClassificationPipeline(mockConfig, true);
      const prodPipeline = new ClassificationPipeline(mockConfig, false);

      expect(testPipeline).toBeInstanceOf(ClassificationPipeline);
      expect(prodPipeline).toBeInstanceOf(ClassificationPipeline);
    });
  });
});

