    it('should detect fabricated evidence not in email content', async () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      const responseWithFakeEvidence = {
        semanticIntent: {
          primaryPurpose: 'notification',
          actionRequired: 'view',
          urgencyLevel: 'high',
        },
        categoryEnhancements: {
          financial: {
            applies: true,
            confidenceBoost: 0.9,
            evidence: {
              quotedPhrases: ['payment due', 'credit card bill'], // These DON'T exist in email
              keywords: ['payment', 'credit'],
              reasoning: 'Contains payment and credit references',
            },
          },
        },
      };

      mockCreate.mockResolvedValueOnce({
        choices: [{ message: { content: JSON.stringify(responseWithFakeEvidence) } }],
