/**
 * Unit Tests for AI Feature Extraction Stage
 *
 * Following TDD approach - these tests MUST FAIL before implementation.
 *
 * This stage uses LangChain OpenAI integration with GPT-4o-mini for semantic feature extraction
 * with JSON schema validation and batch processing support.
 */

import {
  AIFeatureExtractionConfig,
  aiFeatureExtractionStage,
  FeatureExtractionData,
} from '../../src/stages/ai-feature-extraction';
import { ClassificationSession, EmailMessage } from '../../src/types';
import { AttributeContext } from '../../src/types/attribute-context';
import { createClassificationResult } from '../../src/utils/initialization';

// Mock OpenAI client for testing
const mockCreate = jest.fn();
jest.mock('openai', () => ({
  OpenAI: jest.fn().mockImplementation(() => ({
    chat: {
      completions: {
        create: mockCreate,
      },
    },
  })),
}));

describe('AI Feature Extraction Stage', () => {
  const mockConfig: AIFeatureExtractionConfig = {
    openai: {
      apiKey: 'test-api-key',
      model: 'gpt-4o-mini',
      temperature: 0.0,
      responseFormat: 'json_schema',
    },
    prompts: {
      systemPrompt: [
        'You are an expert email analyst that ONLY reports evidence that exists in the actual email content.',
        'Your primary directive is to ground all analysis in exact phrases and keywords from the provided email text.',
      ],
      userPrompt: [
        'Analyze this email and extract ONLY evidence that literally exists in the email text.',
        'You must quote exact phrases and identify actual keywords.',
        '',
        'Email Content:',
        'From: {email.from}',
        'Subject: {email.subject}',
        'Body: {email.body}',
        '',
        'Existing Rule-Based Analysis:',
        '',
        '```xml',
        '<candidateCategories>',
        '{candidateCategories}',
        '</candidateCategories>',
        '',
        '<detectedAttributes>',
        '{detectedAttributes}',
        '</detectedAttributes>',
        '```',
      ],
    },
    featureExtractionSchema: {
      name: 'featureExtraction',
      description: 'Extract semantic features and category enhancements from email content',
      schema: {
        type: 'object',
        properties: {
          semanticIntent: {
            type: 'object',
            properties: {
              primaryPurpose: { type: 'string', enum: ['notification', 'request', 'update', 'alert'] },
              actionRequired: { type: 'string', enum: ['none', 'view', 'respond', 'complete'] },
              urgencyLevel: { type: 'string', enum: ['none', 'low', 'medium', 'high'] },
            },
            required: ['primaryPurpose', 'actionRequired', 'urgencyLevel'],
            additionalProperties: false,
          },
          categoryEnhancements: {
            type: 'object',
            properties: {
              financial: {
                type: 'object',
                properties: {
                  applies: { type: 'boolean' },
                  confidenceBoost: { type: 'number', minimum: -1, maximum: 1 },
                  evidence: {
                    type: 'object',
                    properties: {
                      quotedPhrases: { type: 'array', items: { type: 'string' } },
                      keywords: { type: 'array', items: { type: 'string' } },
                      reasoning: { type: 'string' },
                    },
                    required: ['quotedPhrases', 'keywords', 'reasoning'],
                    additionalProperties: false,
                  },
                },
                required: ['applies', 'confidenceBoost', 'evidence'],
                additionalProperties: false,
              },
              actionable: {
                type: 'object',
                properties: {
                  applies: { type: 'boolean' },
                  confidenceBoost: { type: 'number', minimum: -1, maximum: 1 },
                  evidence: {
                    type: 'object',
                    properties: {
                      quotedPhrases: { type: 'array', items: { type: 'string' } },
                      keywords: { type: 'array', items: { type: 'string' } },
                      reasoning: { type: 'string' },
                    },
                    required: ['quotedPhrases', 'keywords', 'reasoning'],
                    additionalProperties: false,
                  },
                },
                required: ['applies', 'confidenceBoost', 'evidence'],
                additionalProperties: false,
              },
            },
            additionalProperties: false,
          },
        },
        required: ['semanticIntent', 'categoryEnhancements'],
        additionalProperties: false,
      },
      strict: true,
    },
    retryPolicy: {
      maxRetries: 3,
      backoffMs: 1000,
    },
  };

  const mockEmail: EmailMessage = {
    id: 'test-123',
    threadId: 'thread-123',
    gmailLabels: [],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: 'Your monthly statement is ready' },
        { name: 'From', value: 'Bank of Example <statements@bank.example.com>' },
        { name: 'To', value: 'User <user@example.com>' },
      ],
    },
    subject: 'Your monthly statement is ready',
    from: {
      email: 'statements@bank.example.com',
      name: 'Bank of Example',
      raw: 'Bank of Example <statements@bank.example.com>',
    },
    to: [{ email: 'user@example.com', name: 'User', raw: 'User <user@example.com>' }],
    bodyPlain:
      'Your monthly statement for account ending in 1234 is now available. Please log in to view your statement and recent transactions.',
    bodyHtml:
      '<p>Your monthly statement for account ending in 1234 is now available. Please log in to view your statement and recent transactions.</p>',
    date: new Date('2024-01-01T10:00:00Z'),
    isProcessed: false,
    processingPriority: 1,
  };

  const mockSession: ClassificationSession = {
    id: 'session-123',
    startedAt: new Date('2024-01-01T10:00:00Z'),
    emailCount: 1,
    successCount: 0,
    errorCount: 0,
    processingMode: 'parallel',
    batchSize: 1,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },
    configVersion: 'test-version',
    configSnapshot: {},
    errors: [],
    warnings: [],
  };

  // Helper data for populating result objects
  const mockCandidateCategories = {
    financial: { score: 12.5, confidence: 85, decision: 'selected' as const },
    actionable: { score: 8.0, confidence: 70, decision: 'candidate' as const },
  };

  const mockDetectedAttributes = {
    urgency: 'medium' as const,
    domains: ['bank.example.com'],
    structuralPatterns: ['statementNotification'],
  };

  beforeEach(() => {
    jest.clearAllMocks();
    mockCreate.mockReset();
  });

  describe('OpenAI Integration', () => {
    it('should call OpenAI with correct parameters', async () => {
      // Create result with candidateScores and attributeContext
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.candidateScores = {
        financial: { score: 12.5, confidence: 85, decision: 'selected' },
        actionable: { score: 8.0, confidence: 70, decision: 'candidate' },
      };
      result.attributeContext.urgency = 'medium';
      result.attributeContext.domains = ['bank.example.com'];
      result.attributeContext.structuralPatterns = ['statementNotification'];

      const mockOpenAIResponse = {
        choices: [
          {
            message: {
              content: JSON.stringify({
                semanticIntent: {
                  primaryPurpose: 'notification',
                  actionRequired: 'view',
                  urgencyLevel: 'medium',
                },
                categoryEnhancements: {
                  financial: {
                    applies: true,
                    confidenceBoost: 0.8,
                    evidence: {
                      quotedPhrases: ['monthly statement', 'account ending in 1234'],
                      keywords: ['statement', 'account', 'transactions'],
                      reasoning: 'Email contains explicit financial account references and statement language',
                    },
                  },
                  actionable: {
                    applies: true,
                    confidenceBoost: 0.3,
                    evidence: {
                      quotedPhrases: ['Please log in to view'],
                      keywords: ['log', 'view'],
                      reasoning: 'Email requests user action to view statement',
                    },
                  },
                },
              }),
            },
          },
        ],
        usage: { total_tokens: 250 },
      };

      mockCreate.mockResolvedValueOnce(mockOpenAIResponse);

      // Execute stage - mutates result in place
      await aiFeatureExtractionStage(mockEmail, mockSession, result, mockConfig);

      expect(mockCreate).toHaveBeenCalledWith({
        model: 'gpt-4o-mini',
        temperature: 0.0,
        response_format: {
          type: 'json_schema',
          json_schema: {
            name: 'featureExtraction',
            description: 'Extract semantic features and category enhancements from email content',
            schema: mockConfig.featureExtractionSchema.schema,
            strict: true,
          },
        },
        messages: [
          {
            role: 'system',
            content: mockConfig.prompts.systemPrompt.join('\n'),
          },
          {
            role: 'user',
            content: expect.stringContaining('Your monthly statement is ready'),
          },
        ],
      });

      // Check feature extraction data in explainabilityTrace
      expect(result.explainabilityTrace.aiRouting?.aiResponse?.extractedFeatures).toBeDefined();
      expect(
        (result.explainabilityTrace.aiRouting?.aiResponse?.extractedFeatures as FeatureExtractionData)?.semanticIntent
          .primaryPurpose
      ).toBe('notification');
    });

    it('should support backward compatibility with json_object mode', async () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      result.candidateScores = {
        financial: { score: 12.5, confidence: 85, decision: 'selected' },
        actionable: { score: 8.0, confidence: 70, decision: 'candidate' },
      };
      result.attributeContext.urgency = 'medium';
      result.attributeContext.domains = ['bank.example.com'];
      result.attributeContext.structuralPatterns = ['statementNotification'];

      const legacyConfig = {
        ...mockConfig,
        openai: {
          ...mockConfig.openai,
          responseFormat: 'json_object' as const,
        },
        featureExtractionSchema: {
          ...mockConfig.featureExtractionSchema,
          schema: mockConfig.featureExtractionSchema.schema, // Legacy format
        },
      };

      const mockOpenAIResponse = {
        choices: [
          {
            message: {
              content: JSON.stringify({
                semanticIntent: {
                  primaryPurpose: 'notification',
                  actionRequired: 'view',
                  urgencyLevel: 'medium',
                },
                categoryEnhancements: {
                  financial: {
                    applies: true,
                    confidenceBoost: 0.8,
                    evidence: {
                      quotedPhrases: ['monthly statement'],
                      keywords: ['statement'],
                      reasoning: 'Contains financial statement language',
                    },
                  },
                },
              }),
            },
          },
        ],
        usage: { total_tokens: 200 },
      };

      mockCreate.mockResolvedValueOnce(mockOpenAIResponse);

      await aiFeatureExtractionStage(mockEmail, mockSession, result, legacyConfig);

      expect(mockCreate).toHaveBeenCalledWith({
        model: 'gpt-4o-mini',
        temperature: 0.0,
        response_format: { type: 'json_object' },
        messages: [
          {
            role: 'system',
            content: legacyConfig.prompts.systemPrompt.join('\n'),
          },
          {
            role: 'user',
            content: expect.stringContaining('Your monthly statement is ready'),
          },
