  describe('Security and Template Injection Prevention', () => {
    it('should prevent template injection attacks in email content', async () => {
      const result = createClassificationResult('test-123', 'session-123', 0);
      const maliciousEmail = {
        ...mockEmail,
        subject: 'Hello {candidateCategories} inject attempt',
        bodyPlain: 'Your data: {detectedAttributes} and {email.from}',
      };

      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
              content: JSON.stringify({
                semanticIntent: {
                  primaryPurpose: 'notification',
                  actionRequired: 'none',
                  urgencyLevel: 'low',
                },
                categoryEnhancements: {},
              }),
            },
          },
        ],
        usage: { total_tokens: 100 },
      });

      await aiFeatureExtractionStage(maliciousEmail, mockSession, result, mockConfig);

      const calledArgs = mockCreate.mock.calls[0][0];
      const userMessage = calledArgs.messages[1].content;

      // Email content should be sanitized (malicious template attempts neutralized)
      expect(userMessage).toContain('Hello [candidateCategories] inject attempt');
      expect(userMessage).toContain('Your data: [detectedAttributes] and [email.from]');

      // But legitimate JSON in XML blocks should still be present (this is controlled data)
      expect(userMessage).toContain('<candidateCategories>');
      expect(userMessage).toContain('<detectedAttributes>');
      // Result has empty candidateScores in this test, so XML block contains {}
      expect(userMessage).toContain('{}'); // Empty candidateScores

      // The key security feature: email content template chars are sanitized
      const subjectIndex = userMessage.indexOf('Subject:');
      const bodyIndex = userMessage.indexOf('Body:');
      const xmlIndex = userMessage.indexOf('<candidateCategories>');

      // Ensure sanitization only happened in email content sections, not XML sections
      expect(subjectIndex).toBeLessThan(xmlIndex);
      expect(bodyIndex).toBeLessThan(xmlIndex);
    });

